```plantuml
@startuml
skinparam classAttributeIconSize 0

class CreditAccount {
  ...someAttribute
  --
  applyMonthlyInterest()
  applyMonthlyChange()
  ...someOtherMethod()
}

class DebitAccount {
  ...someAttribute
  --
  applyMonthlyInterest()
  deactivateIfUnderBalanced()
  applyMonthlyChange()
  ...someOtherMethod()
}

class PayrollAccount {
  ...someAttribute
  --
  applyMonthlyChange()
  ...someMethod()
}

class Bank {
  accounts:[Account]
  --
  applyAllMonthlyChanges()
}

interface Account {
  applyMonthlyChange()
}

CreditAccount ..|> Account
DebitAccount ..|> Account
PayrollAccount ..|> Account

Bank o-- Account

note right of Bank
applyAllMonthlyChanges(){
  ...
  for every account a in accounts{
    a.applyMonthlyChange
  }
}
end note
@enduml
